INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (80, 'Ensino Fundamental: Anos Finais', 'Língua Portuguesa', '6º Ano', NULL, 'AE13', 'Analisar textos normativos, jurídicos e reivindicatórios, reconhecendo suas marcas linguísticas e estruturais.', NOW());
