INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (100, 'Ensino Fundamental: Anos Finais', 'Língua Portuguesa', '9º Ano', NULL, 'AE3', 'Analisar as características e os efeitos de sentido gerados pela linguagem e organização de textos literários narrativos.', NOW());
