INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (120, 'Ensino Médio', 'Língua Portuguesa', '2ª Série', NULL, 'AE4', 'Analisar textos do campo jornalístico-midiático para produzir textos autorais contextualizados.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (121, 'Ensino Médio', 'Língua Portuguesa', '2ª Série', NULL, 'AE5', 'Analisar textos de divulgação científica de diferentes áreas do conhecimento, identificando suas características e criticando enfoques tendenciosos e superficiais.', NOW());
